/**
 * station-like.ts — re-export and ergonomic alias for the canonical
 * `IStation` contract (defined in `./types`).
 *
 * Architectural status (2026-04-26)
 * ---------------------------------
 * The Pneuma mesh transport story is now multi-variant:
 *
 *   transport          backend                          file
 *   -----------------  -------------------------------  ----------------------
 *   `Station`          HTTP / Fetch (TCP)               station.ts
 *   `StationUds`       UDS + bespoke ASCII headers      station-uds.ts
 *   `StationFlow`      UDS + aeon-flow 10-byte binary   station-flow.ts
 *   `StationFlowUdp`   UDP + aeon-flow 10-byte binary   station-flow-udp.ts
 *   `StationUdsZerocopy` UDS + SCM_RIGHTS fd passing    station-uds-zerocopy.ts
 *
 * Pipeline.ts and cluster.ts type their station array as `IStation[]` so any
 * of these can be plugged in without the orchestrator caring about the wire.
 * This file is the public alias every CALLER should reach for — Pipeline
 * already does, but downstream apps (e.g. mesh-llm.ts) used to declare
 * `Station | StationUds` unions directly. Those are wrong; use `IStation`.
 *
 * What every transport actually shares (the honest contract)
 * ----------------------------------------------------------
 * READ THIS BEFORE EXTENDING `IStation`. The interface in `./types` is the
 * intersection of methods every transport implements:
 *
 *   - `startLayer`, `endLayer`, `role`             — all 5 ✓
 *   - `forward({...}) -> {residual, teleportation?}` — all 5 ✓
 *   - `embed({...}) -> Float32Array`               — all 5 ✓
 *   - `lmHead({...}) -> Float32Array`              — all 5 ✓
 *   - `cobordismEmbed`, `cobordismLmHead`          — all 5 ✓
 *   - `bizarroForward({...}) -> { rejectMask } | null` — all 5 (4 stub null) ✓
 *
 * GAPS (do not promote to `IStation` without filling them):
 *
 *   - `health()` is on `StationUds`, `StationFlow`, `StationFlowUdp` but
 *     NOT on `Station` (HTTP variant uses ad-hoc GETs) and NOT on
 *     `StationUdsZerocopy`. `IStationWithHealth` below is the optional
 *     extension; transport-selector returns the wider type when known.
 *   - Pneuma encoder/decoder methods (`embedAudio`, `forwardEncoderRange`,
 *     `finalizeEncoder`, `encodeStreamingChunk`, `loadAudioContext`,
 *     `decodeStep`) are ONLY on `Station`. The Whisper UDS server backend
 *     does not exist yet; lift these into `IStation` (or a sibling
 *     `IPneumaStation`) ONLY when ≥2 transports support them.
 *
 * Rationale for the optional `teleportation` field
 * ------------------------------------------------
 * Statistical Teleportation deficits ride in response headers (HTTP) or in
 * the aeon-flow `meta` payload (flow transports). Every transport SHOULD
 * surface the structured form when present and `undefined` otherwise. The
 * Pipeline checks `reply.teleportation` and feeds it to the optimizer when
 * non-empty; transports that never carry deficits simply omit the field.
 */

export type { IStation } from './types';

import type { IStation } from './types';

/**
 * Optional health-probe extension. Three of the four mesh transports
 * (StationUds, StationFlow, StationFlowUdp) implement `health()`; the HTTP
 * `Station` and `StationUdsZerocopy` do not. The transport selector
 * narrows to this when the chosen scheme is known to support it.
 *
 * The shape of the returned status object is transport-specific and not
 * part of the contract — callers should treat it as `unknown`.
 */
export interface IStationWithHealth extends IStation {
  health(): Promise<unknown>;
}

/**
 * Type guard: does this station carry a `health()` method?
 */
export function hasHealthProbe(station: IStation): station is IStationWithHealth {
  return typeof (station as IStationWithHealth).health === 'function';
}
